/**
 * @ignore
 * @method
 * @name myriad#parseMyriadMarket
 * @description converts a single raw myriad market into one ccxt market with a list of outcome objects
 * @param {object} raw the raw myriad market object
 * @param {string} [eventSlug] the slug of the parent event
 * @returns {object} a [market structure](https://docs.ccxt.com/#/?id=market-structure)
 */
func  (this *MyriadCore) ParseMyriadMarket(raw any, optionalArgs ...any) any  {
    eventSlug := ccxt.GetArg(optionalArgs, 0, nil)
    _ = eventSlug
    var networkId any = this.SafeString(raw, "networkId")
    var marketId any = this.SafeString(raw, "id")
    var slug any = this.SafeString(raw, "slug", marketId)
    var rawOutcomes any = this.SafeList(raw, "outcomes", []any{})
    var endDate any = this.SafeString(raw, "expiresAt")
    var state any = this.SafeString(raw, "state", "open")
    var active any = ccxt.IsEqual(state, "open")
    var volume24h any = this.SafeNumber(raw, "volume24h")
    var slugBase any = ccxt.Ternary(ccxt.IsTrue((!ccxt.IsEqual(eventSlug, nil))), eventSlug, networkId)
    var marketSymbol any = this.SlugToMarketSymbol(slugBase, slug)
    // the collateral token (address + decimals) is per-market; carry it for on-chain trading
    var tokenObj any = this.SafeDict(raw, "token", map[string]any {})
    var tokenAddress any = this.SafeString(tokenObj, "address")
    var tokenDecimals any = this.SafeInteger(tokenObj, "decimals", 18)
    var outcomes any = []any{}
    for i := 0; ccxt.IsLessThan(i, ccxt.GetArrayLength(rawOutcomes)); i++ {
        var outcome any = this.SafeDict(rawOutcomes, i, map[string]any {})
        var outcomeId any = this.SafeString(outcome, "outcomeId", this.SafeString(outcome, "id", ccxt.ToString(i)))
        var outcomeLabel any = this.SafeString(outcome, "label", this.SafeString(outcome, "title", outcomeId))
        var price any = this.SafeNumber(outcome, "price")
        ccxt.AppendToArray(&outcomes, map[string]any {
            "id": ccxt.Add(ccxt.Add(ccxt.Add(ccxt.Add(networkId, ":"), marketId), "/"), outcomeId),
            "symbol": this.SlugToOutcomeSymbol(slugBase, slug, outcomeLabel),
            "marketSymbol": marketSymbol,
            "label": outcomeLabel,
            "active": active,
            "info": map[string]any {
                "networkId": networkId,
                "marketId": marketId,
                "slug": slug,
                "outcomeId": outcomeId,
                "outcomeLabel": outcomeLabel,
                "outcomePrice": price,
                "volume24h": volume24h,
                "state": state,
                "tradingModel": this.SafeString(raw, "tradingModel", "amm"),
                "tokenAddress": tokenAddress,
                "tokenDecimals": tokenDecimals,
            },
        })
    }
    return map[string]any {
        "id": ccxt.Add(ccxt.Add(networkId, ":"), marketId),
        "symbol": marketSymbol,
        "base": slug,
        "quote": "USDC",
        "settle": nil,
        "baseId": ccxt.Add(ccxt.Add(networkId, ":"), marketId),
        "quoteId": "USDC",
        "settleId": nil,
        "type": "prediction",
        "spot": false,
        "margin": false,
        "swap": false,
        "future": false,
        "option": false,
        "prediction": true,
        "active": active,
        "contract": false,
        "linear": nil,
        "inverse": nil,
        "contractSize": nil,
        "expiry": ccxt.Ternary(ccxt.IsTrue(endDate), this.Parse8601(endDate), nil),
        "expiryDatetime": endDate,
        "strike": nil,
        "optionType": nil,
        "taker": 0.02,
        "maker": 0.02,
        "percentage": true,
        "tierBased": false,
        "feeSide": "get",
        "precision": map[string]any {
            "amount": 0.01,
            "price": 0.001,
        },
        "limits": map[string]any {
            "leverage": map[string]any {
                "min": 1,
                "max": 1,
            },
            "amount": map[string]any {
                "min": 0,
                "max": nil,
            },
            "price": map[string]any {
                "min": 0.001,
                "max": 0.999,
            },
            "cost": map[string]any {
                "min": nil,
                "max": nil,
            },
        },
        "outcomes": outcomes,
        "info": this.Extend(raw, map[string]any {
            "networkId": networkId,
            "marketId": marketId,
            "slug": slug,
            "volume24h": volume24h,
            "state": state,
        }),
        "created": nil,
    }
}
