/**
 * @ignore
 * @method
 * @name myriad#parseWeiOrderBook
 * @description parses an order book whose price and amount levels are 1e18-scaled integer strings
 * @param {object} response the raw orderbook response with bids and asks arrays
 * @param {string} symbol the unified outcome symbol of the order book
 * @returns {object} an [order book structure](https://docs.ccxt.com/#/?id=order-book-structure)
 */
func  (this *MyriadCore) ParseWeiOrderBook(response any, symbol any) any  {
    var rawBids any = this.SafeList(response, "bids", []any{})
    var rawAsks any = this.SafeList(response, "asks", []any{})
    var bids any = []any{}
    for i := 0; ccxt.IsLessThan(i, ccxt.GetArrayLength(rawBids)); i++ {
        var row any = ccxt.GetValue(rawBids, i)
        var rowPrice any = ccxt.Precise.StringDiv(this.SafeString(row, 0), "1000000000000000000")
        var rowAmount any = ccxt.Precise.StringDiv(this.SafeString(row, 1), "1000000000000000000")
        ccxt.AppendToArray(&bids, []any{this.ParseNumber(rowPrice), this.ParseNumber(rowAmount)})
    }
    var asks any = []any{}
    for i := 0; ccxt.IsLessThan(i, ccxt.GetArrayLength(rawAsks)); i++ {
        var row any = ccxt.GetValue(rawAsks, i)
        var rowPrice any = ccxt.Precise.StringDiv(this.SafeString(row, 0), "1000000000000000000")
        var rowAmount any = ccxt.Precise.StringDiv(this.SafeString(row, 1), "1000000000000000000")
        ccxt.AppendToArray(&asks, []any{this.ParseNumber(rowPrice), this.ParseNumber(rowAmount)})
    }
    var timestamp any = this.Milliseconds()
    return map[string]any {
        "symbol": symbol,
        "bids": this.SortBy(bids, 0, true),
        "asks": this.SortBy(asks, 0),
        "timestamp": timestamp,
        "datetime": this.Iso8601(timestamp),
        "nonce": nil,
    }
}
